#!/usr/bin/env bash
# i18n.sh - Internationalization support

LANG_FILE="${CW_DIR:-$HOME/.claude-workspace}/lang"

# Get current language (default: en)
cw_lang() {
  if [[ -f "$LANG_FILE" ]]; then
    cat "$LANG_FILE"
  else
    echo "en"
  fi
}

# Set language
cw_set_lang() {
  local lang="$1"
  if [[ "$lang" != "en" && "$lang" != "ja" ]]; then
    echo "Error: Unsupported language: $lang" >&2
    return 1
  fi
  echo "$lang" > "$LANG_FILE"
}

# Message translations
# Usage: t "message_key"
t() {
  local key="$1"
  local lang
  lang=$(cw_lang)

  case "$lang" in
    ja)
      case "$key" in
        # === Common ===
        "yes") echo "はい" ;;
        "no") echo "いいえ" ;;
        "cancel") echo "キャンセルしました" ;;
        "confirm") echo "続けますか?" ;;
        "continue") echo "続けますか?" ;;
        "create") echo "作成しますか?" ;;
        "created") echo "作成しました" ;;
        "updated") echo "更新しました" ;;
